from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import DBSession
from app.schemas.report import ReportCreate, ReportResponse
from app.services import report as report_service

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def submit_report(data: ReportCreate, db: Session = Depends(DBSession)):
    if not data.image_urls:
        raise HTTPException(status_code=422, detail="Cần ít nhất 1 ảnh")
    return report_service.create_report(db, data)


@router.get("", response_model=list[ReportResponse])
def get_reports(room_id: str | None = None, db: Session = Depends(DBSession)):
    return report_service.list_reports(db, room_id)

