/* ============================================================
   DESIGN TOKENS
   ============================================================ */
:root {
  --color-bg-start: #F8F9FB;
  --color-bg-end: #FFFFFF;
  --color-primary: #4A90FF;
  --color-primary-dark: #2f77e8;
  --color-card-main: #E8F4FF;
  --color-card-white: #FFFFFF;
  --color-text-head: #111111;
  --color-text-body: #333333;
  --color-text-caption: #6B7280;
  --color-border: #D1E3FF;
  --color-error: #FF4D4F;
  --color-success: #4A90FF;

  --radius-card: 20px;
  --radius-card-sm: 16px;
  --radius-thumb: 12px;
  --radius-pill: 26px;

  --shadow-card: 0 8px 24px rgba(74, 144, 255, 0.15);
  --shadow-btn: 0 4px 16px rgba(74, 144, 255, 0.35);
  --shadow-icon: 0 2px 8px rgba(0, 0, 0, 0.10);

  --pad-screen: 16px;
  --gap-section: 24px;
  --gap-card: 16px;

  --font: 'Nunito', -apple-system, 'SF Pro Display', Roboto, sans-serif;

  --transition: 300ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* ============================================================
   RESET & BASE
   ============================================================ */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html {
  font-size: 16px;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

body {
  font-family: var(--font);
  background: linear-gradient(160deg, var(--color-bg-start) 0%, var(--color-bg-end) 100%);
  min-height: 100dvh;
  color: var(--color-text-body);
  overscroll-behavior: none;
}

/* ============================================================
   SCREEN SYSTEM  (slide transitions)
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  overflow-y: auto;
  overflow-x: hidden;
  background: linear-gradient(160deg, var(--color-bg-start) 0%, var(--color-bg-end) 100%);
  transform: translateX(100%);
  transition: transform var(--transition);
  z-index: 1;
  /* Hide scrollbar visually but keep functional */
  scrollbar-width: none;
}
.screen::-webkit-scrollbar { display: none; }

.screen.active {
  transform: translateX(0);
  z-index: 2;
}

.screen.slide-out {
  transform: translateX(-30%);
  z-index: 1;
}

.screen__inner {
  min-height: 100dvh;
  padding: var(--pad-screen);
  padding-bottom: calc(var(--pad-screen) + env(safe-area-inset-bottom));
  display: flex;
  flex-direction: column;
  gap: var(--gap-card);
}

.screen__inner--center {
  justify-content: center;
  align-items: center;
  text-align: center;
  gap: 20px;
}

/* ============================================================
   HEADER
   ============================================================ */
.screen__header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding-top: 12px;
  padding-bottom: 4px;
}

.app-logo {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
}

.app-logo__icon { font-size: 28px; }

.app-logo__text {
  font-size: 15px;
  font-weight: 800;
  color: var(--color-primary);
  letter-spacing: -0.3px;
}

.screen__title {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-text-head);
  line-height: 1.3;
}

.room-label {
  font-size: 20px;
  font-weight: 900;
  color: var(--color-primary);
  letter-spacing: 0.5px;
}

.screen__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--color-text-caption);
  margin-top: 2px;
}

.btn-back {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: none;
  background: var(--color-card-white);
  box-shadow: var(--shadow-icon);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-text-head);
  cursor: pointer;
  flex-shrink: 0;
  transition: transform 150ms, background 150ms;
}

.btn-back:active { transform: scale(0.92); background: var(--color-border); }

/* ============================================================
   BUTTONS
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 52px;
  border-radius: var(--radius-pill);
  border: none;
  cursor: pointer;
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.2px;
  transition: transform 150ms, filter 150ms, box-shadow 150ms;
  -webkit-user-select: none;
  user-select: none;
}

.btn--primary {
  background: var(--color-primary);
  color: #fff;
  box-shadow: var(--shadow-btn);
  padding: 0 28px;
}

.btn--primary:active {
  transform: scale(0.98);
  filter: brightness(0.90);
}

.btn--full { width: 100%; }
.btn--wide { width: min(340px, 100%); }

.btn--ghost {
  background: transparent;
  color: var(--color-primary);
  border: 2px solid var(--color-border);
  padding: 0 24px;
  font-size: 15px;
  font-weight: 600;
}

.btn--ghost:active { transform: scale(0.98); background: var(--color-card-main); }

.btn__icon { font-size: 18px; }
.btn__arrow { font-size: 18px; }

.screen__actions {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-top: 8px;
}

/* ============================================================
   QR SCANNER
   ============================================================ */
.qr-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
  flex: 1;
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 320px;
  aspect-ratio: 3/4;
  border-radius: var(--radius-card);
  overflow: hidden;
  background: #000;
  box-shadow: var(--shadow-card);
}

#qr-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* Corner brackets */
.qr-corner {
  position: absolute;
  width: 32px;
  height: 32px;
  border-color: #fff;
  border-style: solid;
  z-index: 2;
}
.qr-corner--tl { top: 16px; left: 16px; border-width: 3px 0 0 3px; border-radius: 6px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px; border-width: 3px 3px 0 0; border-radius: 0 6px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px; border-width: 0 0 3px 3px; border-radius: 0 0 0 6px; }
.qr-corner--br { bottom: 16px; right: 16px; border-width: 0 3px 3px 0; border-radius: 0 0 6px 0; }

/* Animated scan line */
.qr-scanline {
  position: absolute;
  left: 16px;
  right: 16px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--color-primary), transparent);
  border-radius: 2px;
  top: 20%;
  animation: scanPulse 2s ease-in-out infinite;
  z-index: 2;
}

@keyframes scanPulse {
  0%   { top: 20%; opacity: 0.8; }
  50%  { top: 78%; opacity: 1; }
  100% { top: 20%; opacity: 0.8; }
}

.qr-hint {
  font-size: 14px;
  color: var(--color-text-caption);
  text-align: center;
  max-width: 260px;
}

/* ============================================================
   CAMERA CAPTURE
   ============================================================ */
.camera-view {
  position: relative;
  width: 100%;
  aspect-ratio: 4/3;
  border-radius: var(--radius-card);
  overflow: hidden;
  background: #000;
  box-shadow: var(--shadow-card);
}

#camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.camera-overlay {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 3;
}

.camera-overlay img {
  max-width: 90%;
  max-height: 90%;
  border-radius: 12px;
  object-fit: contain;
}

.photo-counter {
  margin-left: auto;
  background: var(--color-primary);
  color: #fff;
  font-size: 14px;
  font-weight: 700;
  border-radius: 20px;
  padding: 4px 12px;
  white-space: nowrap;
}

/* Thumbnail row */
.thumbnail-row {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 4px 0;
  scrollbar-width: none;
  min-height: 72px;
  align-items: center;
}
.thumbnail-row::-webkit-scrollbar { display: none; }

.thumb {
  position: relative;
  flex-shrink: 0;
  width: 64px;
  height: 64px;
  border-radius: var(--radius-thumb);
  overflow: hidden;
  background: var(--color-card-main);
  box-shadow: var(--shadow-icon);
}

.thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.thumb__del {
  position: absolute;
  top: 2px;
  right: 2px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(0,0,0,0.65);
  border: none;
  color: #fff;
  font-size: 11px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  line-height: 1;
}

/* Add placeholder */
.thumb--add {
  border: 2px dashed var(--color-primary);
  background: transparent;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-primary);
  font-size: 24px;
  font-weight: 300;
  cursor: pointer;
}

/* Shutter button */
.camera-controls {
  display: flex;
  justify-content: center;
  padding: 4px 0;
}

.btn-shutter {
  position: relative;
  width: 72px;
  height: 72px;
  border-radius: 50%;
  border: none;
  background: #fff;
  box-shadow: 0 4px 20px rgba(74,144,255,0.30), 0 0 0 4px rgba(74,144,255,0.15);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 150ms, box-shadow 150ms;
}

.btn-shutter:active {
  transform: scale(0.92);
  box-shadow: 0 2px 8px rgba(74,144,255,0.20), 0 0 0 2px rgba(74,144,255,0.10);
}

.btn-shutter__ring {
  position: absolute;
  inset: 6px;
  border-radius: 50%;
  border: 3px solid var(--color-primary);
}

.btn-shutter__dot {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  background: var(--color-primary);
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card);
  padding: 16px;
  background: var(--color-card-white);
}

.card--main {
  background: var(--color-card-main);
  box-shadow: var(--shadow-card);
}

.card__label {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  font-weight: 700;
  color: var(--color-text-head);
  margin-bottom: 14px;
}

.card__label-icon { font-size: 18px; }

.badge {
  margin-left: auto;
  background: var(--color-primary);
  color: #fff;
  font-size: 12px;
  font-weight: 700;
  border-radius: 12px;
  padding: 2px 10px;
}

/* Horizontal image scroll in report */
.img-scroll {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  scrollbar-width: none;
  padding-bottom: 4px;
}
.img-scroll::-webkit-scrollbar { display: none; }

.img-scroll .thumb {
  flex-shrink: 0;
  width: 72px;
  height: 72px;
}

/* ============================================================
   VOICE RECORDING
   ============================================================ */
.voice-card {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.voice-btn-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.btn-mic {
  position: relative;
  width: 80px;
  height: 80px;
  border-radius: 50%;
  border: none;
  background: var(--color-primary);
  color: #fff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--shadow-btn);
  transition: transform 150ms, box-shadow 150ms, background 150ms;
  overflow: hidden;
}

.btn-mic.recording {
  background: #FF4D4F;
  box-shadow: 0 4px 20px rgba(255,77,79,0.45);
  animation: micPulse 1s ease-in-out infinite;
}

@keyframes micPulse {
  0%, 100% { transform: scale(1); }
  50%       { transform: scale(1.08); }
}

