/**
 * Housekeeping QR Report – Main App
 * Screens: QR Scan → Camera Capture → Room Report → Success
 */

// ── State ──────────────────────────────────────────────────
const state = {
  roomId: null,
  photos: [],          // array of { dataUrl, blob }
  voiceText: '',
  qrScanning: false,
  qrStream: null,
  cameraStream: null,
  recognition: null,
  isRecording: false,
  submitting: false,
};

// ── DOM refs ────────────────────────────────────────────────
const screens = {
  qr:      document.getElementById('screen-qr'),
  camera:  document.getElementById('screen-camera'),
  report:  document.getElementById('screen-report'),
  success: document.getElementById('screen-success'),
};

const $ = (id) => document.getElementById(id);

// ── Toast ───────────────────────────────────────────────────
let toastTimer;
function showToast(msg, duration = 2800) {
  const el = $('toast');
  el.textContent = msg;
  el.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => el.classList.remove('show'), duration);
}

// ── Screen navigation ────────────────────────────────────────
let currentScreen = 'qr';

function navigateTo(name) {
  const prev = screens[currentScreen];
  const next = screens[name];
  if (!next) return;

  prev.classList.add('slide-out');
  next.classList.add('active');

  setTimeout(() => {
    prev.classList.remove('active', 'slide-out');
  }, 320);

  currentScreen = name;
}

function navigateBack(name) {
  const prev = screens[currentScreen];
  const next = screens[name];
  if (!next) return;

  // Reverse: current slides right away, prev reveals from left
  prev.style.transition = 'transform 300ms cubic-bezier(0.4,0,0.2,1)';
  prev.style.transform = 'translateX(100%)';

  next.style.transform = 'translateX(-30%)';
  next.style.transition = 'none';
  next.classList.add('active');

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      next.style.transition = 'transform 300ms cubic-bezier(0.4,0,0.2,1)';
      next.style.transform = 'translateX(0)';
    });
  });

  setTimeout(() => {
    prev.classList.remove('active');
    prev.style.transform = '';
    prev.style.transition = '';
    next.style.transform = '';
    next.style.transition = '';
  }, 320);

  currentScreen = name;
}

// ═══════════════════════════════════════════════════════════
// SCREEN 1 – QR SCAN
// ═══════════════════════════════════════════════════════════

async function startQRCamera() {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 960 } },
      audio: false,
    });
    state.qrStream = stream;
    const video = $('qr-video');
    video.srcObject = stream;
    await video.play();
    $('qr-hint').textContent = 'Đưa mã QR vào khung để quét';
    state.qrScanning = true;
    requestAnimationFrame(tickQR);
  } catch (err) {
    $('qr-hint').textContent = 'Không thể mở camera. Hãy dùng nút Demo.';
    console.warn('QR camera error:', err);
  }
}

function stopQRCamera() {
  state.qrScanning = false;
  if (state.qrStream) {
    state.qrStream.getTracks().forEach((t) => t.stop());
    state.qrStream = null;
  }
}

function tickQR() {
  if (!state.qrScanning) return;
  const video = $('qr-video');
  const canvas = $('qr-canvas');
  if (video.readyState !== video.HAVE_ENOUGH_DATA) {
    requestAnimationFrame(tickQR);
    return;
  }
  canvas.width = video.videoWidth;
  canvas.height = video.videoHeight;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(video, 0, 0);
  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

  const code = jsQR(imageData.data, imageData.width, imageData.height, {
    inversionAttempts: 'dontInvert',
  });

  if (code && code.data) {
    onQRDetected(code.data);
    return;
  }
  requestAnimationFrame(tickQR);
}

function onQRDetected(raw) {
  stopQRCamera();
  // Extract room id: use full value or parse "ROOM:401" style
  let roomId = raw.trim();
  const match = raw.match(/(?:ROOM[:\s]*|PHONG[:\s]*|PHÒNG[:\s]*)(\S+)/i);
  if (match) roomId = match[1];

  enterCameraScreen(roomId);
}

// Start scan on page load automatically
window.addEventListener('DOMContentLoaded', () => {
  startQRCamera();
});

$('btn-start-scan').addEventListener('click', () => {
  if (!state.qrScanning) startQRCamera();
});

$('btn-demo').addEventListener('click', () => {
  stopQRCamera();
  enterCameraScreen('401');
});

// ═══════════════════════════════════════════════════════════
// SCREEN 2 – CAMERA CAPTURE
// ═══════════════════════════════════════════════════════════

async function enterCameraScreen(roomId) {
  state.roomId = roomId;
  state.photos = [];
  $('camera-room-label').textContent = `PHÒNG ${roomId}`;
  updatePhotoCounter();
  renderThumbnails();
  $('btn-continue-camera').style.display = 'none';
  $('camera-overlay').style.display = 'none';
  navigateTo('camera');
  await startCameraCapture();
}

async function startCameraCapture() {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1920 }, height: { ideal: 1440 } },
      audio: false,
    });
    state.cameraStream = stream;
    const video = $('camera-video');
    video.srcObject = stream;
    await video.play();
  } catch (err) {
    showToast('Không thể mở camera chụp ảnh');
    console.warn('Camera error:', err);
  }
}

function stopCameraStream() {
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach((t) => t.stop());
    state.cameraStream = null;
  }
}

$('btn-shutter').addEventListener('click', capturePhoto);

function capturePhoto() {
  if (state.photos.length >= 3) {
    showToast('Đã đạt tối đa 3 ảnh');
    return;
  }
  const video = $('camera-video');
  if (!video.srcObject) {
    showToast('Camera chưa sẵn sàng');
    return;
  }

  const canvas = document.createElement('canvas');
  canvas.width = video.videoWidth || 1280;
  canvas.height = video.videoHeight || 960;
  canvas.getContext('2d').drawImage(video, 0, 0);

  canvas.toBlob((blob) => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ dataUrl, blob });
    updatePhotoCounter();
    renderThumbnails();
    flashShutter();

    if (state.photos.length === 3) {
      // Auto navigate after slight delay
      setTimeout(enterReportScreen, 700);
    } else {
      $('btn-continue-camera').style.display = '';
    }
  }, 'image/jpeg', 0.85);
}

function flashShutter() {
  const overlay = $('camera-overlay');
  const img = overlay.querySelector('#preview-img');
  img.src = state.photos[state.photos.length - 1].dataUrl;
  overlay.style.display = 'flex';
  setTimeout(() => { overlay.style.display = 'none'; }, 600);
}

function updatePhotoCounter() {
  $('photo-counter').textContent = `${state.photos.length} / 3`;
}

function renderThumbnails() {
  const row = $('thumbnail-row');
  row.innerHTML = '';
  state.photos.forEach((p, i) => {
    const div = document.createElement('div');
    div.className = 'thumb';
    div.innerHTML = `
      <img src="${p.dataUrl}" alt="Ảnh ${i + 1}">
      <button class="thumb__del" aria-label="Xoá ảnh ${i + 1}" data-idx="${i}">✕</button>
    `;
    row.appendChild(div);
  });
}

// Delete photo via event delegation
$('thumbnail-row').addEventListener('click', (e) => {
  const btn = e.target.closest('[data-idx]');
  if (!btn) return;
  const idx = parseInt(btn.dataset.idx, 10);
  state.photos.splice(idx, 1);
  updatePhotoCounter();
  renderThumbnails();
  if (state.photos.length === 0) {
    $('btn-continue-camera').style.display = 'none';
  }
});

$('btn-continue-camera').addEventListener('click', enterReportScreen);

$('btn-back-camera').addEventListener('click', () => {
  stopCameraStream();
  state.photos = [];
  navigateBack('qr');
  startQRCamera();
});

// ═══════════════════════════════════════════════════════════
// SCREEN 3 – ROOM REPORT
// ═══════════════════════════════════════════════════════════

function enterReportScreen() {
  stopCameraStream();
  $('report-room-label').textContent = `PHÒNG ${state.roomId}`;
  $('img-count-badge').textContent = `${state.photos.length} ảnh`;
  renderReportImages();
  $('voice-text').value = state.voiceText || '';
  $('report-error').style.display = 'none';
  navigateTo('report');
}

function renderReportImages() {
  const scroll = $('report-img-scroll');
  scroll.innerHTML = '';
  state.photos.forEach((p, i) => {
    const div = document.createElement('div');
    div.className = 'thumb';
    div.innerHTML = `<img src="${p.dataUrl}" alt="Ảnh ${i + 1}">`;
    scroll.appendChild(div);
  });
}

$('btn-back-report').addEventListener('click', () => {
  navigateBack('camera');
  startCameraCapture();
});

// ── Voice recording ─────────────────────────────────────────
const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

function setupVoice() {
  if (!SpeechRecognition) {
    $('voice-status').textContent = 'Trình duyệt không hỗ trợ ghi âm. Nhập tay bên dưới.';
    $('btn-mic').disabled = true;
    $('btn-mic').style.opacity = '0.4';
    return;
  }

  const recognition = new SpeechRecognition();
  recognition.lang = 'vi-VN';
  recognition.continuous = true;
  recognition.interimResults = true;
  state.recognition = recognition;

  let finalTranscript = '';

  recognition.onstart = () => {
    state.isRecording = true;
    $('btn-mic').classList.add('recording');
    $('voice-status').textContent = 'Đang ghi âm... Nhấn lại để dừng';
    $('voice-status').classList.add('active');
    finalTranscript = $('voice-text').value;
  };

  recognition.onresult = (e) => {
    let interim = '';
    for (let i = e.resultIndex; i < e.results.length; i++) {
      if (e.results[i].isFinal) {
        finalTranscript += e.results[i][0].transcript + ' ';
      } else {
        interim += e.results[i][0].transcript;
      }
    }
    $('voice-text').value = finalTranscript + interim;
  };

  recognition.onend = () => {
    state.isRecording = false;
    $('btn-mic').classList.remove('recording');
    $('voice-status').textContent = 'Nhấn để ghi âm';
    $('voice-status').classList.remove('active');
    state.voiceText = $('voice-text').value;
  };

  recognition.onerror = (e) => {
    state.isRecording = false;
    $('btn-mic').classList.remove('recording');
    $('voice-status').textContent = 'Gặp lỗi. Thử lại hoặc nhập tay.';
    $('voice-status').classList.remove('active');
    if (e.error !== 'no-speech') {
      showToast('Lỗi ghi âm: ' + e.error);
    }
  };
}

setupVoice();

$('btn-mic').addEventListener('click', () => {
  if (!state.recognition) return;
  if (state.isRecording) {
    state.recognition.stop();
  } else {
    state.recognition.start();
  }
});

// ── Submit ───────────────────────────────────────────────────
$('btn-submit').addEventListener('click', submitReport);

async function submitReport() {
  if (state.submitting) return;

  const errorEl = $('report-error');
  errorEl.style.display = 'none';

  if (!state.roomId) {
    errorEl.textContent = 'Thiếu mã phòng. Vui lòng quét lại QR.';
    errorEl.style.display = '';
    return;
  }

  if (state.photos.length === 0) {
    errorEl.textContent = 'Cần ít nhất 1 ảnh để gửi báo cáo.';
    errorEl.style.display = '';
    return;
  }

  state.submitting = true;
  const btn = $('btn-submit');
  btn.innerHTML = '<span class="spinner"></span> Đang gửi...';
  btn.disabled = true;

  try {
    // Upload each photo to S3 then collect URLs
    const imageUrls = await uploadPhotos();

    const voiceText = $('voice-text').value.trim() || null;

    await api.post('/api/reports', {
      room_id: state.roomId,
      image_urls: imageUrls,
      voice_text: voiceText,
      note: null,
    });

    enterSuccessScreen();
  } catch (err) {
    errorEl.textContent = err.message || 'Gửi thất bại. Vui lòng thử lại.';
    errorEl.style.display = '';
  } finally {
    state.submitting = false;
    btn.innerHTML = '<span class="btn__icon">📤</span> GỬI BÁO CÁO';
    btn.disabled = false;
  }
}

async function uploadPhotos() {
  const urls = [];

  for (const photo of state.photos) {
    try {
      // Try S3 presigned upload
      const { upload_url, file_url } = await api.post('/api/upload/presigned-url', {
        filename: `room_${state.roomId}_${Date.now()}.jpg`,
      });

      await fetch(upload_url, {
        method: 'PUT',
        body: photo.blob,
        headers: { 'Content-Type': 'image/jpeg' },
      });

      urls.push(file_url);
    } catch (_) {
      // S3 not configured – store data URL as fallback so the report still submits
      urls.push(photo.dataUrl.substring(0, 500));
    }
  }

  return urls;
}

// ═══════════════════════════════════════════════════════════
// SCREEN 4 – SUCCESS
// ═══════════════════════════════════════════════════════════

let countdownTimer;

function enterSuccessScreen() {
  $('success-room-label').textContent = `PHÒNG ${state.roomId}`;
  navigateTo('success');

  // Restart animations by re-inserting elements
  const circle = document.querySelector('.success-circle');
  circle.style.animation = 'none';
  circle.offsetHeight; // reflow
  circle.style.animation = '';

  const checkPath = document.querySelector('.check-path');
  checkPath.style.animation = 'none';
  checkPath.offsetHeight;
  checkPath.style.animation = '';

  // Countdown bar
  clearTimeout(countdownTimer);
  const fill = $('countdown-fill');
  fill.style.transition = 'none';
  fill.style.width = '100%';
  fill.offsetHeight;

  let remaining = 3;
  $('countdown-label').textContent = `Tự động chuyển sau ${remaining}s`;

  setTimeout(() => {
    fill.style.transition = `width ${remaining}s linear`;
    fill.style.width = '0%';
  }, 50);

  const tick = setInterval(() => {
    remaining--;
    $('countdown-label').textContent =
      remaining > 0 ? `Tự động chuyển sau ${remaining}s` : 'Đang chuyển...';
    if (remaining <= 0) {
      clearInterval(tick);
      resetToQR();
    }
  }, 1000);
}

$('btn-new-room').addEventListener('click', resetToQR);

function resetToQR() {
  // Reset all state
  state.roomId = null;
  state.photos = [];
  state.voiceText = '';
  state.isRecording = false;
  if (state.recognition && state.isRecording) state.recognition.stop();

  navigateBack('qr');
  startQRCamera();
}

// ── Sync voiceText on textarea change ───────────────────────
$('voice-text').addEventListener('input', (e) => {
  state.voiceText = e.target.value;
});

// ── Escape HTML helper (used in rendering) ──────────────────
function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

